import{_ as t,o as a,c as o,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Templates for Cost Data","description":"","frontmatter":{"title":"Templates for Cost Data","slug":"templates-for-cost-data"},"headers":[],"relativePath":"marketer-hub/templates-for-cost-data.md","filePath":"marketer-hub/templates-for-cost-data.md"}'),l={name:"marketer-hub/templates-for-cost-data.md"};function i(n,e,s,d,p,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Before you can set up <a href="./cost-data-via-email-import.html">email imports</a> or <a href="./cost-data-via-file-upload.html">file uploads</a> for an ad partner, you first need to create a file template for that ad partner.</p><p>File templates are how Branch is able to map the fields in your cost data to our standard Branch fields.</p><p>By setting up this mapping ahead of time, you can share cost data with Branch in the format that is convenient for you, and we&#39;ll take care of translating and analyzing that information.</p><h3 id="required-fields" tabindex="-1">Required Fields <a class="header-anchor" href="#required-fields" aria-label="Permalink to &quot;Required Fields&quot;">​</a></h3><p>Please note that three fields/columns are <strong>required</strong> in any cost data you send us:</p><ul><li><code>date</code></li><li><code>campaign_name</code></li><li><code>cost</code></li></ul><h2 id="create-new-file-template" tabindex="-1">Create New File Template <a class="header-anchor" href="#create-new-file-template" aria-label="Permalink to &quot;Create New File Template&quot;">​</a></h2><p>To create a new file template:</p><ol><li><p>Navigate to ROI Hub and click on the <strong>Import</strong> <a href="https://dashboard.branch.io/ads/roi-hub/import" target="_blank" rel="noreferrer">tab</a>.</p><p>Click on <strong>Costa data templates</strong>, then the <strong>Create new template</strong> button.</p></li><li><p>You will be taken to the <strong>Start setup</strong> view of the <strong>Create new template</strong> process.</p><p>In this view, you will need to select an <strong>Ad Partner</strong> from the dropdown and give the the template a name. Then click the <strong>Save &amp; Continue</strong> button.</p></li><li><p>In the <strong>Map fields</strong> view, you will need to upload a sample file in CSV format that is representative of the kind of file you expect to import to Branch for that ad partner. All the fields you anticipate using for this ad partner should be included in the sample file.</p><p>Please note that three fields are <strong>required</strong>: <code>date</code>, <code>campaign_name</code>, and <code>cost</code>.</p><p>Click <strong>Upload</strong> to select a sample file from your computer.</p></li><li><p>Once you upload a sample file, you will see the <strong>File column headers</strong> section on the left filled out, and on the right the <strong>Branch fields</strong> are empty. The file column headers have been pulled directly from your sample file, while the corresponding Branch fields need to be filled out.</p><p>Click <strong>Auto Map Fields</strong> to have the Branch fields automatically populated for you. Alternatively, you can select each field individually.</p><p>When your sample file fields are correctly mapped to Branch fields, click the <strong>Save &amp; Continue</strong> button.</p></li><li><p>In the <strong>Validate</strong> view, click the <strong>Run quick validation</strong> button to check that the values in the columns of your sample file are ingestible as expected by Branch. Once your file has successfully been validated, click the <strong>Save &amp; Close</strong> button.</p></li></ol><h2 id="use-a-file-template" tabindex="-1">Use a File Template <a class="header-anchor" href="#use-a-file-template" aria-label="Permalink to &quot;Use a File Template&quot;">​</a></h2><p>Now that you have created a file template, you can use it in either the <strong>File Upload</strong> <a href="https://dashboard.branch.io/ads/roi-hub/import?section=file-upload" target="_blank" rel="noreferrer">view</a> or <strong>Email Importers</strong> <a href="https://dashboard.branch.io/ads/roi-hub/import?section=email-importers" target="_blank" rel="noreferrer">view</a>.</p><p>When selecting an ad partner on those tabs, you will only be able to select ones that have a file template associated with them. All others will be greyed out and have an icon that indicates &quot;<strong>This ad partner does not have a cost file template</strong>&quot; - clicking the icon will take you to a file template setup screen for that ad partner.</p>',13)])])}const m=t(l,[["render",i]]);export{u as __pageData,m as default};
